# geometry_base.spy
# Base geometry types - interfaces, abstract classes, enums, and structs

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

interface IGeometry:
    def area(self) -> float: ...

    def perimeter(self) -> float: ...

@abstract
class Shape:
    color: Color
    position: Point

    def __init__(self, color: Color, position: Point):
        self.color = color
        self.position = position

    @abstract
    def display_name(self) -> str: ...

    @virtual
    def get_color_name(self) -> str:
        if self.color == Color.RED:
            return "Red"
        elif self.color == Color.GREEN:
            return "Green"
        else:
            return "Blue"

