# utils.spy
# Geometry utility functions

from geometry_base import IGeometry, Shape, Color

def describe_shape(shape: IGeometry) -> str:
    area_val: float = shape.area()
    perim_val: float = shape.perimeter()
    return f"Area={area_val:.2f}, Perimeter={perim_val:.2f}"

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def color_from_string(name: str) -> Color:
    if name == "red":
        return Color.RED
    elif name == "green":
        return Color.GREEN
    else:
        return Color.BLUE
